        'currency': currency,
        if (includeFee != null) 'include_fee': includeFee,
        if (extra != null) 'extra': extra,
    };
    return post('/balance/payout', body: bodyMap);
  }

  /// GET /proxy — Get Proxy
  ///
  /// Gets your proxy list.
  Future<Map<String, dynamic>> proxyGet() {
    return get('/proxy');
  }

  /// POST /proxy — Add Proxy
  ///
  /// Add single proxy or proxy list. To add single proxy use this parameters: + **proxy_ip**
  /// (required) - proxy ip or host + **proxy_port** (required) - proxy port
  ///
  /// [proxyIp] Proxy ip or host. Required if **proxy_row** is not specified.
  ///
  /// [proxyPort] Proxy port. Required if **proxy_row** is not specified.
  ///
  /// [proxyUser] Proxy username. Required if **proxy_row** is not specified.
  ///
  /// [proxyPass] Proxy password. Required if **proxy_row** is not specified.
  ///
  /// [proxyRow] Proxy list in String format ip:port:user:pass. Each proxy must be start with new line (use \r\n separator)
  Future<Map<String, dynamic>> proxyAdd({
    String? proxyIp,
    int? proxyPort,
    String? proxyUser,
    String? proxyPass,
    String? proxyRow,
  }) {
    final bodyMap = <String, dynamic>{
        if (proxyIp != null) 'proxy_ip': proxyIp,
        if (proxyPort != null) 'proxy_port': proxyPort,
        if (proxyUser != null) 'proxy_user': proxyUser,
        if (proxyPass != null) 'proxy_pass': proxyPass,
        if (proxyRow != null) 'proxy_row': proxyRow,
    };
    return post('/proxy', body: bodyMap);
  }

  /// DELETE /proxy — Delete Proxy
  ///
  /// Delete single or all proxies.
  Future<Map<String, dynamic>> proxyDelete() {
    return delete('/proxy');
  }

  /// POST /imap — Create IMAP Configuration
  ///
  /// Create an IMAP configuration for a domain.
  ///
  /// [domain] Domain to delete IMAP configuration for.
  ///
  /// [imapServer] IMAP server address.
  ///
  /// [port] IMAP server port.
  ///
  /// [secure] Whether to use a secure connection.
  Future<Map<String, dynamic>> imapCreate({
    required String domain,
    required String imapServer,
    required int port,
    required bool secure,
  }) {
    final bodyMap = <String, dynamic>{
        'domain': domain,
        'imap_server': imapServer,
        'port': port,
        'secure': secure,
    };
    return post('/imap', body: bodyMap);
  }

  /// DELETE /imap — Delete IMAP Configuration
  ///
  /// Delete an IMAP configuration for a domain.
  Future<Map<String, dynamic>> imapDelete() {
    return delete('/imap');
  }

  /// POST /batch — Batch
  ///
  /// Execute multiple API requests at once (separated by comma). Maximum batch jobs is 10.
  /// Following methods are unavailable in Batch: - GET /(item_id)/image - /item/fast-sell
  Future<Map<String, dynamic>> batch({
    Map<String, dynamic>? body,
  }) {
    return post('/batch', body: body);
  }
}
